#include <iostream>
#include <string>

int main() {
    std::string s;
    std::cin >> s;
    int count[10] = {0};
    for (char c : s) {
        if (c >= '0' && c <= '9') {
            count[c - '0']++;
        }
    }
    for (int i = 0; i < 10; i++) {
        std::cout << count[i];
        if (i < 9) std::cout << " ";
    }
    std::cout << std::endl;
    return 0;
}
